import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import i18n from "i18next";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";

export interface Restaurant {
  id: string;
  name: string;
  name_en?: string;
  name_pt?: string;
  address: string;
  lat: number;
  lng: number;
  phone?: string | null;
  opening_hours?: any;
  type: string[];
  type_en?: string[];
  type_pt?: string[];
  rating?: number;
  description?: string | null;
  description_en?: string | null;
  description_pt?: string | null;
  announcement_en?: string | null;
  announcement_pt?: string | null;
  announcement_zh?: string | null;
  image_url?: string | null;
  cover_image_url?: string | null;
  website_url?: string | null;
  show_website_button?: boolean;
  visible?: boolean;
  template?: string;
  owner_avatar_url?: string | null;
  owner_bio?: string | null;
  owner_bio_en?: string | null;
  owner_bio_pt?: string | null;
  photo_story_zh?: string | null;
  photo_story_en?: string | null;
  photo_story_pt?: string | null;
  country?: string | null;
  city?: string | null;
  created_at: string;
}

// Map common city names across languages for cross-language search
const CITY_NAME_VARIANTS: Record<string, string[]> = {
  "香港": ["Hong Kong"], "澳门": ["Macau", "Macao"], "东京": ["Tokyo"], "大阪": ["Osaka"],
  "里斯本": ["Lisbon", "Lisboa"], "波尔图": ["Porto"], "伦敦": ["London"], "巴黎": ["Paris"],
  "纽约": ["New York"], "首尔": ["Seoul"], "柏林": ["Berlin"], "马德里": ["Madrid"], "罗马": ["Rome", "Roma"],
  "hong kong": ["香港"], "macau": ["澳门"], "tokyo": ["东京"], "osaka": ["大阪"],
  "lisbon": ["里斯本"], "london": ["伦敦"], "paris": ["巴黎"], "new york": ["纽约"], "seoul": ["首尔"],
};

function getCitySearchVariants(query: string): string[] {
  return CITY_NAME_VARIANTS[query.toLowerCase()] || CITY_NAME_VARIANTS[query] || [];
}

export const useRestaurants = (searchQuery?: string, typeFilter?: string) => {
  return useQuery({
    queryKey: ["restaurants", searchQuery, typeFilter],
    queryFn: async () => {
      let query = supabase
        .from("restaurants")
        .select("id,name,name_en,name_pt,address,lat,lng,phone,opening_hours,type,type_en,type_pt,rating,image_url,cover_image_url,visible,template,photo_story_zh,photo_story_en,photo_story_pt,created_at,store_level,country,city")
        .eq("visible", true)
        .order("rating", { ascending: false });

      if (searchQuery) {
        // Search across all language variants of name and address
        // Also map common city name translations for cross-language search
        const searchTerms = [searchQuery, ...getCitySearchVariants(searchQuery)];
        const orConditions = searchTerms.flatMap(term => [
          `name.ilike.%${term}%`,
          `name_en.ilike.%${term}%`,
          `name_pt.ilike.%${term}%`,
          `address.ilike.%${term}%`,
        ]);
        query = query.or([...new Set(orConditions)].join(','));
      }

      if (typeFilter) {
        // Split multiple types by comma, expand each to all DB language variants
        const types = typeFilter.split(',');
        const allVariants = types.flatMap(type => getTypeFilterValues(type));
        const uniqueVariants = [...new Set(allVariants)];
        const orConditions = uniqueVariants.flatMap(variant => [
          `type.cs.{${variant}}`,
          `type_en.cs.{${variant}}`,
          `type_pt.cs.{${variant}}`
        ]);
        query = query.or(orConditions.join(','));
      }

      const { data, error } = await query;

      if (error) throw error;
      return data as Restaurant[];
    },
  });
};

export const useRestaurant = (id: string) => {
  return useQuery({
    queryKey: ["restaurant", id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("restaurants")
        .select("*")
        .eq("id", id)
        .single();

      if (error) throw error;
      return data as Restaurant;
    },
    enabled: !!id,
  });
};

export const useFavoriteIds = () => {
  const { user } = useAuth();

  return useQuery({
    queryKey: ["favorite-ids", user?.id],
    queryFn: async () => {
      if (!user) return [];

      const { data, error } = await supabase
        .from("favorites")
        .select("restaurant_id")
        .eq("user_id", user.id);

      if (error) throw error;
      return data.map(f => f.restaurant_id);
    },
    enabled: !!user,
  });
};

// Keep the old name for backwards compatibility but make it use the new one
export const useFavorites = useFavoriteIds;

export const useToggleFavorite = () => {
  const { user } = useAuth();
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (restaurantId: string) => {
      if (!user) throw new Error("Must be logged in");

      // Check if already favorited
      const { data: existing } = await supabase
        .from("favorites")
        .select("id")
        .eq("user_id", user.id)
        .eq("restaurant_id", restaurantId)
        .maybeSingle();

      if (existing) {
        // Remove favorite
        const { error } = await supabase
          .from("favorites")
          .delete()
          .eq("id", existing.id);

        if (error) throw error;
        return { action: "removed" };
      } else {
        // Add favorite
        const { error } = await supabase
          .from("favorites")
          .insert({
            user_id: user.id,
            restaurant_id: restaurantId,
          });

        if (error) throw error;
        return { action: "added" };
      }
    },
    onSuccess: (result) => {
      queryClient.invalidateQueries({ queryKey: ["favorites"] });
      toast.success(i18n.t(result.action === "added" ? "toast.favoriteAdded" : "toast.favoriteRemoved"));
    },
    onError: (error: any) => {
      if (error.message === "Must be logged in") {
        toast.error(i18n.t("toast.signInToFavorite"));
      } else {
        toast.error(i18n.t("toast.favoritesUpdateFailed"));
      }
    },
  });
};

