// Reverse map: translate any localized tag back to English key (for filtering)
const reverseTypeTagMap: Record<string, string> = {};
// Build reverse map from ALL languages
for (const lang of Object.keys(typeTagTranslations)) {
  const map = typeTagTranslations[lang];
  if (map) {
    for (const [en, localized] of Object.entries(map)) {
      reverseTypeTagMap[localized] = en;
    }
  }
}
// Also map English keys to themselves
for (const key of Object.keys(typeTagTranslations.zh || {})) {
  reverseTypeTagMap[key] = key;
}

/**
 * Given a localized type label, return the English key.
 */
export function getTypeEnglishKey(localizedTag: string): string {
  return reverseTypeTagMap[localizedTag] || localizedTag;
}

// Map of filter category → all DB type_en values that belong to it
const TYPE_CATEGORY_MEMBERS: Record<string, string[]> = {
  "Chinese": ["Chinese", "Chinese Restaurant", "Cantonese", "Shanghainese", "Roast Duck", "Ramen", "拉面", "ラーメン"],
  "Japanese": ["Japanese", "Japanese Restaurant", "Sushi", "Kaiseki", "Ramen", "拉面", "ラーメン"],
  "Ramen": ["Ramen", "拉面", "ラーメン"],
  "Asian": ["Asian", "Asian Fusion", "Thai", "Vietnamese", "Korean", "Indian", "Nepalese", "Nepalese cuisine", "Progressive Indian"],
  "Historic": ["Historic Restaurant", "Historic Café", "Historic Pub", "Historic Tavern", "Historic Hotel", "Historic Hotel Restaurant", "Historic Brewery", "Historic Building", "Historic", "Century-old Restaurant"],
  "Michelin": ["Michelin", "Michelin Restaurant", "Three Michelin Stars", "Fine Dining", "Innovative Cuisine"],
  "Café": ["Café", "Coffee", "Coffee Shop", "Specialty Coffee", "Starbucks"],
  "Bar": ["Bar"],
  "Dessert": ["Dessert", "Pastry", "Patisserie"],
  "Gelato": ["Gelato"],
  "Hotel": ["Hotel"],
  "Virtual Kitchen": ["Virtual Kitchen"],
  "Landmark": ["Landmark", "Modern Architecture", "Unique Architecture"],
  "Other": ["Other", "British", "Spanish", "French Cuisine", "Steakhouse", "Fast Food"],
};

/**
 * Given a localized type label, return all DB-stored variants for filtering.
 * Expands to all member types in the category and their zh/pt translations.
 */
export function getTypeFilterValues(localizedTag: string): string[] {
  const enKey = getTypeEnglishKey(localizedTag);
  const members = TYPE_CATEGORY_MEMBERS[enKey] || [enKey];
  const values = new Set<string>();
  for (const member of members) {
    values.add(member);
    // Also add zh/pt translations from the reverse map
    const zh = typeTagTranslations.zh?.[member];
    const pt = typeTagTranslations.pt?.[member];
    if (zh) values.add(zh);
    if (pt) values.add(pt);
    // Add any known DB variants via reverse lookup
    for (const lang of Object.keys(typeTagTranslations)) {
      const localized = typeTagTranslations[lang]?.[member];
      if (localized) values.add(localized);
    }
  }
  return Array.from(values);
}

/**
 * Translate a type tag to the display language.
 * Input can be in any DB language (zh, en, pt). Output is the current UI language.
 * Falls back to the original tag if no translation found.
 */
export function getTypeDisplayLabel(tag: string, lang: string): string {
  // If already in the target language's map values, return as-is
  const targetMap = typeTagTranslations[lang];
  if (targetMap) {
    // Check if tag is already a value in this language
    if (Object.values(targetMap).includes(tag)) return tag;
    // Try direct English key match
    if (targetMap[tag]) return targetMap[tag];
    // Try reverse lookup: tag might be zh/pt, find English key first
    const enKey = reverseTypeTagMap[tag];
    if (enKey && targetMap[enKey]) return targetMap[enKey];
  }
  return tag;
}

// Fixed standardized store type categories for filtering
const STANDARD_TYPE_KEYS = [
  "Chinese",
  "Japanese",
  "Ramen",
  "Asian",
  "Historic",
  "Michelin",
  "Café",
  "Bar",
  "Dessert",
  "Gelato",
  "Hotel",
  "Virtual Kitchen",
  "Landmark",
  "Other",
];

export const useRestaurantTypes = () => {
  return useQuery({
    queryKey: ["restaurant-types", i18n.language],
    queryFn: () => {
      // Return localized labels for the 9 standardized store types
      return STANDARD_TYPE_KEYS.map(key => getTypeDisplayLabel(key, i18n.language));
    },
  });
};

export const useRestaurantCountries = () => {
  return useQuery({
    queryKey: ["restaurant-countries"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("restaurants")
        .select("country")
        .eq("visible", true)
        .not("country", "is", null);
      if (error) throw error;
      const countries = [...new Set(data.map(r => r.country).filter(Boolean))] as string[];
      return countries.sort();
    },
  });
};

export const useRestaurantCities = (country?: string | null) => {
  return useQuery({
    queryKey: ["restaurant-cities", country],
    queryFn: async () => {
      let query = supabase
        .from("restaurants")
        .select("city")
        .eq("visible", true)
        .not("city", "is", null);
      if (country) {
        query = query.eq("country", country);
      }
      const { data, error } = await query;
      if (error) throw error;
      const cities = [...new Set(data.map(r => r.city).filter(Boolean))] as string[];
      return cities.sort();
    },
  });
};
